CREATE PROC [dbo].[CREATE_B2B] @FromDate datetime,@ToDate datetime AS DECLARE @GSTIN AS CHAR(16) DECLARE @HSNCODETablename AS CHAR(16) DECLARE @HSNCodeField AS CHAR(12) DECLARE @IMTableQry AS VARCHAR(500) SET @HSNCODETablename='##HSNCODETABLE' IF OBJECT_ID('tempdb..' + @HSNCODETablename) IS NOT NULL EXEC ('DROP TABLE ' + @HSNCODETablename) IF OBJECT_ID('dbo.B2B','U') IS NOT NULL DROP TABLE b2b IF OBJECT_ID('dbo.b2b_Info','U') IS NOT NULL DROP TABLE b2b_Info SELECT @HSNCodeField=Txt FROM SysParam WHERE ParamCode='AnalysisCodeUsedToStoreHSNCode' SET @IMTableQry= 'SELECT StockNo,'+ @HSNCodeField +' AS HSNCODE INTO ' + @HSNCODETablename + ' FROM ItemMaster' EXEC (@IMTableQry) SELECT @GSTIN=Txt FROM SysParam WHERE ParamCode='LocalSTaxRegnNo' SELECT * INTO b2b FROM ( SELECT CUST.LSTNo AS 'GSTIN/UIN of Recipient', (STD.DocNoPrefix + '/' + CONVERT(Varchar(6),STD.DocNo)) AS 'Invoice Number', STD.DocDt AS 'Invoice date', CAST(STH.NetDocValue AS Decimal(10,2)) AS 'Invoice Value', CAST(LEFT(CUST.LSTNo,2) as Varchar(64)) AS 'Place Of Supply', 'N' AS 'Reverse Charge', 'Regular' AS 'Invoice Type', '' AS 'E-Commerce GSTIN', CAST((STD.stdTaxComp1Per + STD.stdTaxComp2Per) AS Decimal(10,2))  AS 'Rate', CAST(SUM(STD.TaxAV1) AS Decimal(10,2)) AS 'Taxable Value', CAST(SUM((CASE WHEN LEFT(CUST.LSTNo,2)=LEFT(@GSTIN,2) THEN STD.TaxComp3 ELSE STD.TaxComp2 END)) AS Decimal(10,2))  AS 'Cess Amount' FROM StktrnDtls STD INNER JOIN StkTrnHdr STH ON STD.DocNoPrefix=STH.DocNoPrefix AND STD.DocNo=STH.DocNo AND STD.TrnType=STH.TrnType INNER JOIN Customers CUST ON CUST.Code=STH.PartyId WHERE ISNULL(CUST.LSTNO,'')<>'' AND STH.TrnType=2100 AND LEN(CUST.LSTNO)>=15 AND STD.DocDt>=@FromDate AND STD.DocDt<=@ToDate AND STD.DocDt>=(SELECT dt FROM SYSPARAM WHERE ParamCode='GSTImplementationDate') AND CUST.LSTNo<>@GSTIN AND STD.docentvoidind = 0 GROUP BY STD.DocNoPrefix, STD.DocNo, STD.DocDt, CUST.LSTNO, STD.stdTaxComp1Per, STD.stdTaxComp2Per, STD.stdTaxComp3Per, CAST(STH.NetDocValue AS Decimal(10,2))  UNION ALL SELECT CUST.LSTNo AS 'GSTIN/UIN of Recipient', STD.DocNoPrefix + '/' + CONVERT(VARCHAR(6),STD.DocNo) AS 'Invoice Number', STD.DocDt AS 'Invoice date', CAST(STH.NETDOCVALUE AS Decimal(10,2)) AS 'Invoice Value', CAST(LEFT(CUST.LSTNo,2) as Varchar(64)) AS 'Place Of Supply', 'N' AS 'Reverse Charge', 'Regular' AS 'Invocie Type', '' AS 'E-Commerce GSTIN', CAST((STD.stdTaxComp1Per + STD.stdTaxComp2Per ) AS Decimal(10,2))  AS 'Rate', CAST(SUM(STD.DocEntNetValue-STD.DocEntTax) AS Decimal(10,2)) AS 'Total Taxable Value', CAST(SUM((CASE WHEN LEFT(CUST.LSTNo,2)=LEFT(@GSTIN,2) THEN STD.TaxComp3 ELSE 'STD.TaxComp2' END)) AS Decimal(10,2))  AS 'CESS Amount' FROM  StktrnDtls STD INNER JOIN StkTrnHdr STH ON STD.DocNoPrefix=STH.DocNoPrefix AND STD.DocNo=STH.DocNo AND STD.TrnType=STH.TrnType INNER JOIN ChainStores CUST ON CUST.Code=STH.PartyId WHERE ISNULL(CUST.LSTNO,'')<>'' AND   STH.TrnType=2200 AND LEN(CUST.LSTNO)>=15 AND STD.DocDt>=@FromDate AND STD.DocDt<=@ToDate AND STD.DocDt>=(SELECT dt FROM SYSPARAM WHERE ParamCode='GSTImplementationDate') AND CUST.LSTNo<>@GSTIN AND STD.docentvoidind = 0 GROUP BY STD.DocNoPrefix, STD.DocNo, STD.DocDt, CUST.LSTNO, CAST(STH.NETDOCVALUE AS Decimal(10,2)), STD.stdTaxComp1Per, STD.stdTaxComp2Per, STD.stdTaxComp3Per ) AS Temp1 UPDATE  CD set [Place of Supply] = Cast([Place of Supply] as Varchar(4)) + '-' + GL.Descr FROM B2B CD Inner JOIN (SELECT Code,DEscr FROM GenLookUp WHERE RecID=92 ) GL on CD.[Place of Supply] = GL.Code SELECT COUNT(DISTINCT [GSTIN/UIN of Recipient]) AS [No. Of Receipents],COUNT(DISTINCT [Invoice Number]) AS [No. Of Invoices],SUM([Invoice Value]) AS [Total Invoice value],SUM([Taxable Value]) AS [Total Taxable value],SUM([CESS AMOUNT]) AS [Total Cess] INTO B2B_Info FROM B2B IF OBJECT_ID('B2B_Header','U') IS NULL CREATE TABLE B2B_Header ([Summary For B2B(4)] Char(1) ) INSERT INTO InfoTable Values('B2B',2,'<<Default>>','B2B',1) 